// ============================================================
// Mini's IPA Repo — Weighted Fuzzy Search Engine
// ============================================================
// Score weights: exact name (1.0) > prefix (0.95) > dev (0.7) > desc (0.4)
// Implements character-level fuzzy matching with word-boundary bonuses.

import type { AppData, SearchResult } from './types';
import { escapeHtml } from './utils';

/**
 * Score how well `query` matches `field`, weighted by field importance.
 *
 * Scoring tiers (highest → lowest), each multiplied by `weight`:
 *   1.00 — exact match
 *   0.95 — prefix match
 *   0.80–0.85 — contiguous substring (0.85 if at a word boundary)
 *   0.65 — word-initial acronym match (e.g. "yt" → "YouTube")
 *   0.30–0.50 — fuzzy subsequence (score scales with character density)
 *
 * @param query   Lowercased, trimmed search string.
 * @param field   Lowercased field value to match against.
 * @param weight  Field importance multiplier (name=1.0, dev=0.7, desc=0.4).
 * @param precomputedWordStarts  Optional cached result of getWordStartIndices(field).
 * @returns Score in [0, weight] and the highlight ranges within `field`, or score=0 for no match.
 */
function scoreField(
    query: string,
    field: string,
    weight: number,
    precomputedWordStarts?: number[],
): { score: number; ranges: [number, number][] } {
    if (!field) return { score: 0, ranges: [] };

    // Exact match
    if (field === query) {
        return { score: 1.0 * weight, ranges: [[0, field.length]] };
    }

    // Prefix match
    if (field.startsWith(query)) {
        return { score: 0.95 * weight, ranges: [[0, query.length]] };
    }

    // Substring match (contiguous)
    const idx = field.indexOf(query);
    if (idx >= 0) {
        // Bonus if match starts at a word boundary
        const boundaryBonus = idx === 0 || !isWordChar(field.charCodeAt(idx - 1)) ? 0.05 : 0;
        return {
            score: (0.8 + boundaryBonus) * weight,
            ranges: [[idx, idx + query.length]],
        };
    }

    // Word-initial matching: check if each query char matches the start of a word
    const wordStarts = precomputedWordStarts ?? getWordStartIndices(field);
    const wordMatch = matchWordInitials(query, field, wordStarts);
    if (wordMatch) {
        return { score: 0.65 * weight, ranges: wordMatch };
    }

    // Fuzzy subsequence match
    const fuzzy = fuzzySubsequence(query, field);
    if (fuzzy) {
        // Score based on how tightly packed the matches are
        const spread = fuzzy[fuzzy.length - 1][1] - fuzzy[0][0];
        const density = query.length / Math.max(spread, 1);
        return {
            score: Math.min(0.5, 0.3 + density * 0.2) * weight,
            ranges: fuzzy,
        };
    }

    return { score: 0, ranges: [] };
}

/** Check if a character code is a word character (alphanumeric or underscore) */
function isWordChar(code: number): boolean {
    return (
        (code >= 48 && code <= 57)  || // 0-9
        (code >= 65 && code <= 90)  || // A-Z
        (code >= 97 && code <= 122) || // a-z
        code === 95                     // _
    );
}

/** Find indices where words start in a string */
export function getWordStartIndices(str: string): number[] {
    if (!str) return [];
    const indices: number[] = [0];
    for (let i = 1; i < str.length; i++) {
        if (!isWordChar(str.charCodeAt(i - 1)) && isWordChar(str.charCodeAt(i))) {
            indices.push(i);
        }
    }
    return indices;
}

/**
 * Acronym/initials match: each query character must match the first character of
 * consecutive words in `field` (e.g. "yt" matches "YouTube", "gcal" matches "Google Calendar").
 *
 * @param query       Lowercased query string.
 * @param field       Lowercased field to search.
 * @param wordStarts  Indices of word-start characters (from getWordStartIndices).
 * @returns Array of single-character [start, end] ranges, or null if no match.
 */
function matchWordInitials(
    query: string,
    field: string,
    wordStarts: number[],
): [number, number][] | null {
    if (wordStarts.length < query.length) return null;

    const ranges: [number, number][] = [];
    let wi = 0;

    for (let qi = 0; qi < query.length; qi++) {
        let found = false;
        while (wi < wordStarts.length) {
            if (field[wordStarts[wi]] === query[qi]) {
                ranges.push([wordStarts[wi], wordStarts[wi] + 1]);
                wi++;
                found = true;
                break;
            }
            wi++;
        }
        if (!found) return null;
    }

    return ranges;
}

/**
 * Fuzzy subsequence match: every character in `query` must appear in `field`
 * in the same left-to-right order, but not necessarily contiguously.
 * Contiguous matched characters are merged into a single range for efficiency.
 *
 * @param query  Lowercased query string.
 * @param field  Lowercased field to search.
 * @returns Merged [start, end] highlight ranges, or null if any query char is missing.
 */
function fuzzySubsequence(query: string, field: string): [number, number][] | null {
    const ranges: [number, number][] = [];
    let fi = 0;

    for (let qi = 0; qi < query.length; qi++) {
        let found = false;
        while (fi < field.length) {
            if (field[fi] === query[qi]) {
                // Merge with previous range if contiguous
                if (ranges.length > 0 && ranges[ranges.length - 1][1] === fi) {
                    ranges[ranges.length - 1][1] = fi + 1;
                } else {
                    ranges.push([fi, fi + 1]);
                }
                fi++;
                found = true;
                break;
            }
            fi++;
        }
        if (!found) return null;
    }

    return ranges;
}

/** Run fuzzy search across all apps. Returns scored, ranked results. */
export function fuzzySearch(query: string, apps: AppData[]): SearchResult[] {
    const q = query.toLowerCase().trim();
    if (!q) {
        return apps.map((app) => ({ app, score: 1, nameMatches: [] }));
    }

    const results: SearchResult[] = [];

    for (const app of apps) {
        const nameResult = scoreField(q, app._searchName, 1.0, app._wordStartsName);
        const devResult = scoreField(q, app._searchDev, 0.7, app._wordStartsDev);
        const descResult = scoreField(q, app._searchDesc, 0.4, app._wordStartsDesc);

        // Take the best matching field
        let bestScore = 0;
        let bestMatches: [number, number][] = [];

        if (nameResult.score >= devResult.score && nameResult.score >= descResult.score) {
            bestScore = nameResult.score;
            bestMatches = nameResult.ranges;
        } else if (devResult.score >= descResult.score) {
            bestScore = devResult.score;
            bestMatches = []; // Don't highlight name for developer matches
        } else {
            bestScore = descResult.score;
            bestMatches = []; // Don't highlight name for description matches
        }

        if (bestScore > 0) {
            results.push({
                app,
                score: bestScore,
                // bestMatches already holds nameResult.ranges when name won, and []
                // when dev/desc won. Using the ternary here is wrong: it would show
                // name highlights even when dev/desc scored higher (if name also
                // matched), making the highlighted text not match the search basis.
                nameMatches: bestMatches,
            });
        }
    }

    // Stable sort: highest score first, then alphabetical for ties
    results.sort((a, b) => {
        if (b.score !== a.score) return b.score - a.score;
        return a.app.name.localeCompare(b.app.name);
    });

    return results;
}

/** Render app name with <mark> tags around matched ranges */
export function highlightMatches(name: string, matches: [number, number][]): string {
    if (!matches.length) return escapeHtml(name);

    let result = '';
    let cursor = 0;

    // Ranges are always produced in ascending order by scoreField / fuzzySubsequence,
    // so no sort is needed. We still merge adjacent/overlapping ranges defensively.
    const merged: [number, number][] = [];
    for (const range of matches) {
        if (merged.length > 0 && range[0] <= merged[merged.length - 1][1]) {
            merged[merged.length - 1][1] = Math.max(merged[merged.length - 1][1], range[1]);
        } else {
            merged.push([range[0], range[1]]);
        }
    }

    for (const [start, end] of merged) {
        if (cursor < start) {
            result += escapeHtml(name.slice(cursor, start));
        }
        result += `<mark>${escapeHtml(name.slice(start, end))}</mark>`;
        cursor = end;
    }

    if (cursor < name.length) {
        result += escapeHtml(name.slice(cursor));
    }

    return result;
}

