// ============================================================
// Mini's IPA Repo — Virtual Scroll Engine
// ============================================================
// Renders only cards whose bounding box intersects a 2x viewport
// overscan region. Recycles DOM nodes from an object pool.

import type { AppData } from './types';
import { CONFIG } from './config';

export interface VirtualScrollCallbacks {
    /** Called to bind app data to a DOM node */
    bindCard: (el: HTMLElement, app: AppData, index: number) => void;
    /** Called when a card is clicked */
    onCardClick: (appId: string) => void;
    /** Called to create a fresh card DOM node */
    createCardNode: () => HTMLElement;
}

interface PooledNode {
    el: HTMLElement;
    appId: string | null;
}

export class VirtualScroll {
    private container: HTMLElement;
    private innerContainer: HTMLElement;
    private items: AppData[] = [];
    private itemIndexMap = new Map<string, number>(); // O(1) id → index lookup
    private pool: PooledNode[] = [];
    private activeNodes = new Map<string, PooledNode>();
    private callbacks: VirtualScrollCallbacks;
    private columns = 1;
    private rowHeight: number = CONFIG.CARD_ROW_HEIGHT;
    private gap: number = CONFIG.CARD_GAP;
    private containerTop = 0;
    private rafId = 0;
    private resizeObserver: ResizeObserver | null = null;
    private resizeRafId = 0;
    private scrollHandler: (() => void) | null = null;

    // Cached layout metrics — updated only in computeLayout()
    private cachedPaddingLeft = 0;
    private cachedPaddingRight = 0;
    private cachedContainerWidth = 0;
    private cachedAvailableWidth = 0;
    private cachedColWidth = 0;

    constructor(container: HTMLElement, callbacks: VirtualScrollCallbacks) {
        this.container = container;
        this.callbacks = callbacks;

        // Create inner scroll container for absolute positioning
        this.innerContainer = document.createElement('div');
        this.innerContainer.className = 'vs-inner';
        this.innerContainer.setAttribute('role', 'list');
        this.innerContainer.setAttribute('aria-label', 'App list');
        this.container.appendChild(this.innerContainer);

        // Initialize pool
        for (let i = 0; i < CONFIG.CARD_POOL_SIZE; i++) {
            const el = callbacks.createCardNode();
            el.style.position = 'absolute';
            el.style.left = '0';
            el.style.top = '0';
            el.style.display = 'none';
            el.setAttribute('role', 'listitem');
            this.innerContainer.appendChild(el);
            this.pool.push({ el, appId: null });
        }

        this.setupListeners();
        this.computeLayout();
    }

    private setupListeners(): void {
        // Scroll handler with RAF throttle
        this.scrollHandler = () => {
            if (this.rafId) return;
            this.rafId = requestAnimationFrame(() => {
                this.rafId = 0;
                this.render();
            });
        };

        window.addEventListener('scroll', this.scrollHandler, { passive: true });

        // Resize observer for responsive columns — debounced to prevent feedback loops
        this.resizeObserver = new ResizeObserver(() => {
            if (this.resizeRafId) cancelAnimationFrame(this.resizeRafId);
            this.resizeRafId = requestAnimationFrame(() => {
                this.resizeRafId = 0;
                this.computeLayout();
                this.render();
            });
        });
        this.resizeObserver.observe(this.container);

        // Click delegation
        this.innerContainer.addEventListener('click', (e) => {
            const card = (e.target as HTMLElement).closest('[data-app-id]') as HTMLElement | null;
            if (!card) return;
            const btn = (e.target as HTMLElement).closest('button');
            if (btn) return; // Let button handlers work
            const appId = card.dataset.appId;
            if (appId) this.callbacks.onCardClick(appId);
        });

        // Keyboard navigation
        this.innerContainer.addEventListener('keydown', (e) => {
            const card = (e.target as HTMLElement).closest('[data-app-id]') as HTMLElement | null;
            if (!card) return;

            if (e.key === 'Enter' || e.key === ' ') {
                // Native <button> elements handle their own activation via click events.
                // Without this guard, pressing Space/Enter on the GET button would both
                // trigger the download (native) and open the modal (this handler).
                if ((e.target as HTMLElement).closest('button')) return;
                e.preventDefault();
                const appId = card.dataset.appId;
                if (appId) this.callbacks.onCardClick(appId);
                return;
            }

            if (['ArrowRight', 'ArrowLeft', 'ArrowDown', 'ArrowUp'].includes(e.key)) {
                e.preventDefault();
                this.navigateGrid(card, e.key);
            }
        });
    }

    private navigateGrid(currentCard: HTMLElement, key: string): void {
        const appId = currentCard.dataset.appId;
        if (!appId) return;
        const currentIndex = this.itemIndexMap.get(appId);
        if (currentIndex == null) return;

        let nextIndex = currentIndex;
        switch (key) {
            case 'ArrowRight': nextIndex = Math.min(currentIndex + 1, this.items.length - 1); break;
            case 'ArrowLeft': nextIndex = Math.max(currentIndex - 1, 0); break;
            case 'ArrowDown': nextIndex = Math.min(currentIndex + this.columns, this.items.length - 1); break;
            case 'ArrowUp': nextIndex = Math.max(currentIndex - this.columns, 0); break;
        }

        if (nextIndex !== currentIndex) {
            const nextApp = this.items[nextIndex];
            // Ensure the target is rendered, then focus it
            this.scrollToIndex(nextIndex);
            requestAnimationFrame(() => {
                const node = this.activeNodes.get(nextApp.id);
                if (node) node.el.focus({ preventScroll: true });
            });
        }
    }

    /** Compute grid layout metrics — called only on resize, NOT per frame */
    private computeLayout(): void {
        const style = getComputedStyle(this.container);
        this.cachedContainerWidth = this.container.clientWidth;
        this.cachedPaddingLeft = parseFloat(style.paddingLeft) || 0;
        this.cachedPaddingRight = parseFloat(style.paddingRight) || 0;
        this.cachedAvailableWidth = this.cachedContainerWidth - this.cachedPaddingLeft - this.cachedPaddingRight;

        // Responsive columns: match the CSS grid breakpoints
        if (this.cachedAvailableWidth >= 900) {
            this.columns = 3;
        } else if (this.cachedAvailableWidth >= 540) {
            this.columns = 2;
        } else {
            this.columns = 1;
        }

        // Read actual gap from CSS custom property with JS fallback (M6)
        const gapValue = style.getPropertyValue('--vs-gap')?.trim();
        this.gap = gapValue ? (parseInt(gapValue, 10) || CONFIG.CARD_GAP) : CONFIG.CARD_GAP;

        // Cache column width so render() never needs getComputedStyle
        this.cachedColWidth = (this.cachedAvailableWidth - (this.columns - 1) * this.gap) / this.columns;

        this.containerTop = this.container.getBoundingClientRect().top + window.scrollY;
    }

    /** Update items and re-render */
    setItems(items: AppData[]): void {
        this.items = items;

        // Rebuild O(1) index lookup map
        this.itemIndexMap.clear();
        for (let i = 0; i < items.length; i++) {
            this.itemIndexMap.set(items[i].id, i);
        }

        // Update total height
        const rows = Math.ceil(items.length / this.columns);
        const totalHeight = rows * (this.rowHeight + this.gap) - this.gap;
        this.innerContainer.style.height = `${Math.max(totalHeight, 0)}px`;

        // Snapshot values before iterating — releaseNode deletes from activeNodes,
        // and mutating a Map while iterating it causes entries to be silently skipped.
        for (const node of [...this.activeNodes.values()]) {
            this.releaseNode(node);
        }

        this.render();
    }

    /** Get a node from the pool, allocating a new one if the pool is exhausted. */
    private acquireNode(): PooledNode {
        if (this.pool.length > 0) {
            return this.pool.pop()!;
        }
        // Pool exhausted (e.g. wide viewport + multi-column + large overscan).
        // Allocate on demand rather than silently dropping items from the grid.
        const el = this.callbacks.createCardNode();
        el.style.position = 'absolute';
        el.style.left = '0';
        el.style.top = '0';
        el.style.display = 'none';
        el.setAttribute('role', 'listitem');
        this.innerContainer.appendChild(el);
        return { el, appId: null };
    }

    /** Return a node to the pool */
    private releaseNode(node: PooledNode): void {
        if (node.appId) {
            this.activeNodes.delete(node.appId);
        }
        node.el.style.display = 'none';
        node.appId = null;
        this.pool.push(node);
    }

    /**
     * Core render loop — called on every scroll event (RAF-throttled) and resize.
     *
     * Algorithm:
     *  1. Determine which rows intersect a 2× viewport overscan window.
     *  2. Build `visibleIds` — the set of app IDs that should be rendered.
     *  3. Release any active nodes whose ID is no longer in `visibleIds` → back to pool.
     *  4. For each visible item, acquire a pooled node (or allocate on demand),
     *     call `bindCard` to stamp app data onto it, then position it via `translate3d`
     *     using pre-cached layout metrics (no `getComputedStyle` per frame).
     */
    render(): void {
        if (this.items.length === 0) {
            for (const [, node] of this.activeNodes) {
                this.releaseNode(node);
            }
            return;
        }

        const scrollTop = window.scrollY;
        const viewportH = window.innerHeight;
        const overscan = viewportH * 2; // 2x viewport overscan

        // Which rows are visible?
        const gridTop = this.containerTop;
        const rowPitch = this.rowHeight + this.gap;
        const totalRows = Math.ceil(this.items.length / this.columns);

        const relativeTop = scrollTop - gridTop - overscan;
        const relativeBottom = scrollTop + viewportH - gridTop + overscan;

        const startRow = Math.max(0, Math.floor(relativeTop / rowPitch));
        const endRow = Math.min(totalRows - 1, Math.ceil(relativeBottom / rowPitch));

        const startIndex = startRow * this.columns;
        const endIndex = Math.min((endRow + 1) * this.columns, this.items.length);

        // Determine which items should be visible
        const visibleIds = new Set<string>();
        for (let i = startIndex; i < endIndex; i++) {
            visibleIds.add(this.items[i].id);
        }

        // Release nodes that are no longer visible
        for (const [id, node] of this.activeNodes) {
            if (!visibleIds.has(id)) {
                this.releaseNode(node);
            }
        }

        // Bind/position visible items using cached layout metrics (no getComputedStyle!)
        const paddingLeft = this.cachedPaddingLeft;
        const colWidth = this.cachedColWidth;

        for (let i = startIndex; i < endIndex; i++) {
            const app = this.items[i];
            let node = this.activeNodes.get(app.id);

            if (!node) {
                node = this.acquireNode();
                node.appId = app.id;
                this.activeNodes.set(app.id, node);
                this.callbacks.bindCard(node.el, app, i);
            }

            // Position the node
            const row = Math.floor(i / this.columns);
            const col = i % this.columns;
            const x = paddingLeft + col * (colWidth + this.gap);
            const y = row * rowPitch;

            node.el.style.transform = `translate3d(${x}px, ${y}px, 0)`;
            node.el.style.width = `${colWidth}px`;
            node.el.style.height = `${this.rowHeight}px`;
            node.el.style.display = '';
        }
    }

    /** Scroll to make a specific item index visible */
    scrollToIndex(index: number): void {
        const row = Math.floor(index / this.columns);
        const rowPitch = this.rowHeight + this.gap;
        const targetY = this.containerTop + row * rowPitch;
        const viewportH = window.innerHeight;

        if (targetY < window.scrollY || targetY + this.rowHeight > window.scrollY + viewportH) {
            // Use 'instant' so window.scrollY is updated synchronously before the
            // render RAF fires. Smooth scroll leaves scrollY at the old position
            // when the RAF ticks, so the target item wouldn't be rendered yet and
            // the subsequent focus() call would silently fail.
            window.scrollTo({
                top: targetY - viewportH / 3,
                behavior: 'instant' as ScrollBehavior,
            });
        }

        // Force render to ensure the node exists
        requestAnimationFrame(() => this.render());
    }

    /** Update row height (e.g., after measuring actual card height) */
    setRowHeight(height: number): void {
        if (height > 0 && height !== this.rowHeight) {
            this.rowHeight = height;
            const rows = Math.ceil(this.items.length / this.columns);
            const totalHeight = rows * (this.rowHeight + this.gap) - this.gap;
            this.innerContainer.style.height = `${Math.max(totalHeight, 0)}px`;
            this.render();
        }
    }

    /** Get current DOM node count */
    getActiveNodeCount(): number {
        return this.activeNodes.size;
    }

    /** Clean up */
    destroy(): void {
        if (this.rafId) cancelAnimationFrame(this.rafId);
        if (this.resizeRafId) cancelAnimationFrame(this.resizeRafId);
        if (this.scrollHandler) window.removeEventListener('scroll', this.scrollHandler);
        this.resizeObserver?.disconnect();
        this.innerContainer.remove();
        // Release JS references so GC can collect DOM nodes and AppData objects
        this.activeNodes.clear();
        this.itemIndexMap.clear();
        this.pool.length = 0;
    }
}
