// ============================================================
// Mini's IPA Repo — Toast Notification System
// ============================================================
// Spring-animated slide-up toasts with grouping for rapid fires.

import type { ToastType, ToastAction } from './types';
import { CONFIG } from './config';

let toastEl: HTMLElement | null = null;
let toastTimer: ReturnType<typeof setTimeout> | null = null;
let toastTransitionTimer: ReturnType<typeof setTimeout> | null = null;
let toastQueue: Array<{ msg: string; type: ToastType; action?: ToastAction }> = [];
let isShowing = false;

function getToastEl(): HTMLElement | null {
    if (!toastEl) {
        toastEl = document.getElementById('toast');
    }
    return toastEl;
}

export function showToast(msg: string, type: ToastType = 'info', action?: ToastAction): void {
    const el = getToastEl();
    if (!el) return;

    // If already showing, queue this toast (cap at 5 to prevent unbounded growth)
    if (isShowing) {
        if (toastQueue.length >= 5) {
            toastQueue.shift(); // Drop oldest queued toast
        }
        toastQueue.push({ msg, type, action });
        // Group: if queue is getting long, replace the current toast immediately
        if (toastQueue.length > 2) {
            dismissToast();
        }
        return;
    }

    presentToast(el, msg, type, action);
}

function presentToast(
    el: HTMLElement,
    msg: string,
    type: ToastType,
    action?: ToastAction,
): void {
    isShowing = true;

    if (toastTimer) {
        clearTimeout(toastTimer);
        toastTimer = null;
    }

    // Build content
    el.innerHTML = '';
    const textSpan = document.createElement('span');
    textSpan.textContent = msg;
    el.appendChild(textSpan);

    if (action) {
        const actionBtn = document.createElement('button');
        actionBtn.type = 'button';
        actionBtn.textContent = action.text;
        actionBtn.addEventListener('click', () => {
            // I10: wrap callback so a throw doesn't prevent toast dismissal
            try { action.callback(); } catch (err) { console.error('[toast] action callback threw:', err); }
            dismissToast();
        });
        el.appendChild(actionBtn);
    }

    // Set ARIA urgency
    el.setAttribute(
        'aria-live',
        type === 'error' || type === 'warning' ? 'assertive' : 'polite',
    );

    el.className = `toast ${type} show`;

    toastTimer = setTimeout(() => {
        dismissToast();
    }, CONFIG.TOAST_DURATION);
}

function dismissToast(): void {
    const el = getToastEl();
    if (!el) return;

    el.classList.remove('show');
    isShowing = false;

    if (toastTimer) {
        clearTimeout(toastTimer);
        toastTimer = null;
    }

    // Cancel any already-pending transition timer before scheduling a new one,
    // so rapid dismissals don't queue up multiple presentToast calls.
    if (toastTransitionTimer) {
        clearTimeout(toastTransitionTimer);
        toastTransitionTimer = null;
    }

    // Show next queued toast after exit animation
    if (toastQueue.length > 0) {
        const next = toastQueue.shift();
        if (!next) return;
        toastTransitionTimer = setTimeout(() => {
            toastTransitionTimer = null;
            presentToast(el, next.msg, next.type, next.action);
        }, 200);
    }
}
