// ============================================================
// Mini's IPA Repo — Configuration Constants
// ============================================================

// Derive the site base URL from the current location so that forks,
// staging environments, and local dev all work without code changes.
// e.g. https://oofmini.github.io/Minis-Repo/ on production,
//      http://localhost:5173/  on Vite dev server.
const _raw = window.location.origin + window.location.pathname;
const _BASE_URL = _raw.endsWith('/') ? _raw : _raw + '/';

export const CONFIG = {
    /** mini.json endpoint */
    API_ENDPOINT: `${_BASE_URL}mini.json`,

    /** Fallback icon if app icon fails to load */
    FALLBACK_ICON: './apps/repo-icon.png',

    /** Featured app bundle ID */
    FEATURED_BUNDLE_ID: 'com.spotify.client',

    /** Search debounce in ms */
    SEARCH_DEBOUNCE: 150,

    /** Toast display duration in ms */
    TOAST_DURATION: 4000,

    /** Network fetch timeout in ms */
    FETCH_TIMEOUT: 10_000,

    /** Virtual scroll: pool size (max DOM card nodes) */
    CARD_POOL_SIZE: 24,

    /** Card row height in px (iOS-style cell: icon + text) */
    CARD_ROW_HEIGHT: 88,

    /** Gap between cards in px */
    CARD_GAP: 12,

    /** SW update check interval (30 min) */
    SW_UPDATE_INTERVAL: 30 * 60 * 1000,

    /** Max recent searches to store */
    MAX_RECENT_SEARCHES: 5,

    /** IndexedDB database name (main app) */
    IDB_NAME: 'minis-repo',

    /** IndexedDB version */
    IDB_VERSION: 1,

    /** IndexedDB database name used by the service worker */
    IDB_SW_NAME: 'minis-repo-sw',

    /** Spring animation: bouncy entry */
    SPRING_BOUNCY: 'cubic-bezier(0.175, 0.885, 0.32, 1.275)',

    /** Spring animation: smooth exit */
    SPRING_SMOOTH: 'cubic-bezier(0.4, 0, 0.2, 1)',

    /** Repo manifest URL for display */
    MANIFEST_URL: `${_BASE_URL}mini.json`,

    /** App base URL — always ends with '/' so hash fragments concatenate cleanly */
    BASE_URL: _BASE_URL,
} as const;
