import type { Category } from './types';
import type { Permission, RawPermission } from './types';
import { CONFIG } from './config';

// ── HTML Escaping ──────────────────────────────────────────

export function escapeHtml(str: string): string {
    if (!str) return '';
    // Pure-regex escaping — no DOM dependency, works in workers and test environments.
    return str.replace(/[&<>]/g, (c) => c === '&' ? '&amp;' : c === '<' ? '&lt;' : '&gt;');
}

export function escapeAttr(str: string): string {
    if (!str) return '';
    return str
        .replace(/&/g, '&amp;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;');
}

// ── Color Utilities ────────────────────────────────────────

const DEFAULT_TINT = '#a78bfa';

export function sanitizeTintColor(color: string | undefined): string {
    if (color && /^#[0-9A-Fa-f]{6}$/.test(color)) return color;
    return DEFAULT_TINT;
}

export function hexToRgba(hex: string, alpha: number): string {
    if (!hex || hex.length < 7) return `rgba(167, 139, 250, ${alpha})`;
    const r = parseInt(hex.slice(1, 3), 16);
    const g = parseInt(hex.slice(3, 5), 16);
    const b = parseInt(hex.slice(5, 7), 16);
    if (isNaN(r) || isNaN(g) || isNaN(b)) return `rgba(167, 139, 250, ${alpha})`;
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
}

// ── Formatting ─────────────────────────────────────────────

export function formatSize(bytes: number | undefined): string {
    if (bytes == null || typeof bytes !== 'number' || bytes < 0) return 'Unknown';
    if (bytes === 0) return '0 KB';
    if (bytes >= 1_073_741_824) return `${(bytes / 1_073_741_824).toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })} GB`;
    if (bytes >= 1_048_576) return `${Math.round(bytes / 1_048_576).toLocaleString()} MB`;
    return `${Math.round(bytes / 1024).toLocaleString()} KB`;
}

export function formatRelativeTime(dateStr: string): string {
    if (!dateStr) return '';
    // Only append time component for date-only strings (YYYY-MM-DD).
    // Full ISO timestamps already have a 'T'; appending again would produce
    // an invalid string like "2024-01-15T12:00:00ZT00:00:00Z".
    const normalized = dateStr.includes('T') ? dateStr : dateStr + 'T00:00:00Z';
    const date = new Date(normalized);
    const ts = date.getTime();
    if (Number.isNaN(ts)) return '';

    const diffDays = Math.floor((Date.now() - ts) / 86_400_000);

    // diffDays = 0: today. diffDays = -1: within one day of UTC normalisation —
    // treat as "Today" (timezone tolerance). diffDays < -1: a genuine future date
    // (e.g. a pre-release entry). Show the absolute date rather than "Today".
    if (diffDays >= -1 && diffDays <= 0) return 'Today';
    if (diffDays < -1) {
        return date.toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' });
    }
    if (diffDays === 1) return 'Yesterday';
    if (diffDays < 7) return `${diffDays}d ago`;
    if (diffDays < 30) return `${Math.floor(diffDays / 7)}w ago`;
    if (diffDays < 365) return `${Math.floor(diffDays / 30)}mo ago`;
    return `${Math.floor(diffDays / 365)}y ago`;
}

// ── Category Inference ─────────────────────────────────────

export function inferCategory(bundleId: string): Category {
    const bid = bundleId.toLowerCase();
    // IMPORTANT: 'youtubemusic' must be checked before the 'youtube'/'video' test
    // below — otherwise YouTube Music would be classified as Video.
    if (bid.includes('youtubemusic')) return 'Music';
    if (bid.includes('spotify') || bid.includes('music')) return 'Music';
    if (bid.includes('youtube') || bid.includes('video')) return 'Video';
    if (bid.includes('social') || bid.includes('tweet') || bid.includes('twitter')) return 'Social';
    if (
        bid.includes('editor') ||
        bid.includes('inshot') ||
        bid.includes('photo') ||
        bid.includes('reface') ||
        bid.includes('doublicatapp')
    )
        return 'Creative';
    return 'Utilities';
}

// ── ID Generation ──────────────────────────────────────────

export function generateId(bundleId: string, index: number): string {
    if (bundleId) return bundleId.toLowerCase();
    return `unknown-${index}`;
}

// ── URL Validation ─────────────────────────────────────────

export function isValidDownloadUrl(url: string): boolean {
    if (!url || typeof url !== 'string') return false;
    try {
        const parsed = new URL(url);
        return parsed.protocol === 'https:' && parsed.hostname.includes('.');
    } catch {
        return false;
    }
}

// ── Debounce ───────────────────────────────────────────────

export type DebouncedFn<T extends (...args: unknown[]) => void> =
    ((...args: Parameters<T>) => void) & { cancel(): void };

export function debounce<T extends (...args: unknown[]) => void>(
    fn: T,
    ms: number,
): DebouncedFn<T> {
    let timer: ReturnType<typeof setTimeout>;
    const debounced = (...args: Parameters<T>) => {
        clearTimeout(timer);
        timer = setTimeout(() => fn(...args), ms);
    };
    debounced.cancel = () => clearTimeout(timer);
    return debounced;
}

// ── IndexedDB helpers ──────────────────────────────────────

// Cache the open connection so repeated idbGet/idbSet calls share one handle.
let _idb: IDBDatabase | null = null;
let _idbOpenPromise: Promise<IDBDatabase | null> | null = null;

function idbOpen(): Promise<IDBDatabase | null> {
    if (_idb) return Promise.resolve(_idb);
    if (_idbOpenPromise) return _idbOpenPromise;

    _idbOpenPromise = new Promise((resolve) => {
        try {
            const req = indexedDB.open(CONFIG.IDB_NAME, CONFIG.IDB_VERSION);
            req.onupgradeneeded = () => {
                const db = req.result;
                if (!db.objectStoreNames.contains('searches'))
                    db.createObjectStore('searches', { keyPath: 'key' });
                if (!db.objectStoreNames.contains('data'))
                    db.createObjectStore('data', { keyPath: 'key' });
            };
            req.onsuccess = () => {
                _idb = req.result;
                _idbOpenPromise = null;
                // Clear cache if the connection is closed externally (e.g. version bump).
                _idb.onclose = () => { _idb = null; _idbOpenPromise = null; };
                resolve(_idb);
            };
            req.onerror = () => {
                _idbOpenPromise = null;
                resolve(null);
            };
        } catch {
            _idbOpenPromise = null;
            resolve(null);
        }
    });

    return _idbOpenPromise;
}

export async function idbGet<T>(storeName: string, key: string): Promise<T | undefined> {
    const db = await idbOpen();
    if (!db) return undefined;
    return new Promise((resolve) => {
        try {
            const tx = db.transaction(storeName, 'readonly');
            const get = tx.objectStore(storeName).get(key);
            get.onsuccess = () => resolve(get.result?.value as T);
            get.onerror = () => resolve(undefined);
        } catch {
            resolve(undefined);
        }
    });
}

export async function idbSet(storeName: string, key: string, value: unknown): Promise<void> {
    const db = await idbOpen();
    if (!db) return;
    return new Promise((resolve) => {
        try {
            const tx = db.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).put({ key, value });
            tx.oncomplete = () => resolve();
            tx.onerror = () => { console.error('[idb] write failed:', tx.error); resolve(); };
        } catch {
            resolve();
        }
    });
}

// ── Permission normalization ───────────────────────────────

export function normalizePermissions(perms: RawPermission[]): Permission[] {
    if (!Array.isArray(perms)) return [];
    return perms
        .map((p) => {
            if (typeof p === 'string') return { type: p, usageDescription: '' };
            if (typeof p === 'object' && p !== null && 'type' in p) {
                return { type: p.type, usageDescription: p.usageDescription ?? '' };
            }
            return null;
        })
        .filter((p): p is Permission => p !== null);
}
